def is_palindrome(s: str) -> bool:
    filtered = ''.join(filter(str.isalnum, s)).lower()
    return filtered == filtered[::-1]

def fibonacci(n: int) -> int:
    if n < 0:
        raise ValueError("n must be a non-negative integer")
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a

